DROP TABLE IF EXISTS `opportunities`;
CREATE TABLE `opportunities`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `lead_id` int(11) NOT NULL COMMENT '关联线索ID（商机必须从线索创建）',
