  `task_id` int(11) NOT NULL COMMENT '所属任务ID',
  `team_leader_id` int(11) NOT NULL COMMENT '组长ID',
  `customer_unit` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '客户单位',
  `required_products` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '客户需要的产品',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '商机描述',
  `expected_amount` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '预计金额',
  `status` enum('CREATED','IN_PROGRESS','LOST','WON') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '商机状态',
  `lost_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '流失原因',
  `won_amount` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '转定金额',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `status_changed_at` datetime NULL DEFAULT NULL COMMENT '状态变更时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `ix_opportunities_opportunity_no`(`opportunity_no`) USING BTREE,
  UNIQUE INDEX `idx_lead_id`(`lead_id`) USING BTREE,
  INDEX `task_id`(`task_id`) USING BTREE,
  INDEX `team_leader_id`(`team_leader_id`) USING BTREE,
  INDEX `ix_opportunities_id`(`id`) USING BTREE,
  CONSTRAINT `fk_opportunities_lead_id` FOREIGN KEY (`lead_id`) REFERENCES `leads` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `opportunities_ibfk_1` FOREIGN KEY (`task_id`) REFERENCES `tasks` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `opportunities_ibfk_2` FOREIGN KEY (`team_leader_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 18 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

