-- Table structure for option_configs
-- ----------------------------
DROP TABLE IF EXISTS `option_configs`;
CREATE TABLE `option_configs`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `option_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '选项类型：requirement_direction 或 product',
