  INDEX `idx_option_type`(`option_type`) USING BTREE,
  INDEX `idx_parent_id`(`parent_id`) USING BTREE,
  CONSTRAINT `fk_option_configs_parent_id` FOREIGN KEY (`parent_id`) REFERENCES `option_configs` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 66 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '选项配置表' ROW_FORMAT = Dynamic;

