-- ----------------------------
-- Table structure for tasks
-- ----------------------------
DROP TABLE IF EXISTS `tasks`;
CREATE TABLE `tasks`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `task_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务名称',
  `sales_unit` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '面向的销售单位（多个值用逗号分隔）',
  `start_date` date NOT NULL COMMENT '任务开始日期',
  `end_date` date NOT NULL COMMENT '任务结束日期',
  `fde_count` int(11) NOT NULL COMMENT 'FDE支撑人员数量',
  `customer_unit` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客户单位',
  `industry_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '行业类型',
  `requirement_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '详细需求内容（拜访线索单内容）',
  `expected_visit_time` datetime(6) NULL DEFAULT NULL COMMENT '预期拜访时间',
  `status` enum('draft','pending','rejected','confirmed','detail_required','detail_submitted','dispatched','in_progress','completed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft',
  `rejection_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '拒绝原因',
  `initiator_id` int(11) NOT NULL COMMENT '发起人ID',
  `initiator_role` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '任务创建时发起人使用的角色（task_initiator或sales_contact）',
  `manager_id` int(11) NULL DEFAULT NULL COMMENT '总管ID',
  `sales_contact_id` int(11) NULL DEFAULT NULL COMMENT '销售接口人ID',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `confirmed_at` datetime NULL DEFAULT NULL COMMENT '确认时间',
  `detail_submitted_at` datetime NULL DEFAULT NULL COMMENT '详细需求提交时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `initiator_id`(`initiator_id`) USING BTREE,
  INDEX `manager_id`(`manager_id`) USING BTREE,
  INDEX `sales_contact_id`(`sales_contact_id`) USING BTREE,
  INDEX `ix_tasks_id`(`id`) USING BTREE,
  CONSTRAINT `tasks_ibfk_1` FOREIGN KEY (`initiator_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `tasks_ibfk_2` FOREIGN KEY (`manager_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `tasks_ibfk_3` FOREIGN KEY (`sales_contact_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 86 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

