  `real_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '真实姓名',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '邮箱',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '手机号',
  `role` enum('TASK_INITIATOR','MANAGER','SALES_CONTACT','TEAM_LEADER','MEMBER') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '角色',
  `sales_unit` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '所属销售单位',
  `is_active` tinyint(1) NULL DEFAULT NULL COMMENT '是否激活',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '头像URL',
  `failed_login_attempts` int(11) NULL DEFAULT 0,
  `locked_until` datetime NULL DEFAULT NULL,
  `approval_status` enum('pending','approved','rejected') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending' COMMENT '审核状态',
  `rejection_reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '拒绝原因',
  `approved_at` datetime NULL DEFAULT NULL COMMENT '审核通过时间',
  `approved_by` int(11) NULL DEFAULT NULL COMMENT '审核人ID',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `ix_users_username`(`username`) USING BTREE,
  INDEX `ix_users_id`(`id`) USING BTREE,
  INDEX `fk_users_approved_by`(`approved_by`) USING BTREE,
  CONSTRAINT `fk_users_approved_by` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 56 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of users
-- ----------------------------

-- ----------------------------
-- Table structure for visit_log_maintenance_logs
-- ----------------------------
DROP TABLE IF EXISTS `visit_log_maintenance_logs`;
CREATE TABLE `visit_log_maintenance_logs`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `visit_log_id` int(11) NOT NULL COMMENT '线索维护记录ID',
  `operator_id` int(11) NOT NULL COMMENT '操作人ID',
  `operated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '操作时间',
  `fields_changed` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '本次变更字段 JSON 数组',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_vl_maint_visit`(`visit_log_id`) USING BTREE,
  INDEX `idx_vl_maint_time`(`operated_at`) USING BTREE,
  INDEX `fk_vl_maint_user`(`operator_id`) USING BTREE,
  CONSTRAINT `fk_vl_maint_user` FOREIGN KEY (`operator_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_vl_maint_visit` FOREIGN KEY (`visit_log_id`) REFERENCES `visit_logs` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '线索维护窄域更新操作记录' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of visit_log_maintenance_logs
-- ----------------------------

-- ----------------------------
-- Table structure for visit_logs
-- ----------------------------
DROP TABLE IF EXISTS `visit_logs`;
CREATE TABLE `visit_logs`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `work_order_id` int(11) NOT NULL COMMENT '工单ID',
  `member_id` int(11) NOT NULL COMMENT '成员ID',
  `visit_date` date NOT NULL COMMENT '拜访日期',
  `visit_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '拜访内容',
  `visit_object_position` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '拜访对象职位',
  `opportunity_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '商机编号',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `group_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '组别（工单组长所属 FDE 组名快照）',
  `customer_unit` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客户单位快照',
  `industry` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '行业（手动填写）',
  `enterprise_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '企业类型（大型企业/小微企业/中型企业）',
  `customer_visit_address` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客户拜访地址快照',
  `customer_manager_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客户经理姓名快照',
  `customer_manager_contact` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客户经理联系方式快照',
  `escort_staff` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '陪跑人员（手动填写）',
  `has_decision_authority` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '拜访对象权限：建议权、决策权、无',
  `sales_unit` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '所属销售单位快照（任务 sales_unit）',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '备注',
  `has_requirement_scenario_sorted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '客户是否梳理过需求场景',
  `requirement_scenario_category` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '需求场景分类（JSON数组格式，支持多选）',
  `has_clue` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否有线索',
  `clue_related_products` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '线索对应产品（JSON数组格式，支持多选）',
  `is_customized_development` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否定开',
  `customized_development_requirements` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '定开要求（是否定开为是时填写）',
  `project_amount` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '项目金额（万元）',
  `current_stage` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '当前阶段',
  `promotion_progress` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '推进进展',
  `promotion_progress_history` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '推进进展追加历史 JSON：[{at,user_id,user_name,text},...]',
  `promotion_requirements` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '推进要求',
  `stage_effort_breakdown` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '阶段人员与时长(JSON数组：[{sub_phase,people,days}])',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `work_order_id`(`work_order_id`) USING BTREE,
  INDEX `member_id`(`member_id`) USING BTREE,
  INDEX `ix_visit_logs_id`(`id`) USING BTREE,
  INDEX `ix_visit_logs_opportunity_no`(`opportunity_no`) USING BTREE,
  CONSTRAINT `visit_logs_ibfk_1` FOREIGN KEY (`work_order_id`) REFERENCES `work_orders` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `visit_logs_ibfk_2` FOREIGN KEY (`member_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 70 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of visit_logs
-- ----------------------------

-- ----------------------------
-- Table structure for work_orders
-- ----------------------------
DROP TABLE IF EXISTS `work_orders`;
CREATE TABLE `work_orders`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `work_order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单编号',
  `task_id` int(11) NOT NULL COMMENT '所属任务ID',
  `detail_requirement_id` int(11) NULL DEFAULT NULL COMMENT '关联的详细需求ID',
  `team_leader_id` int(11) NULL DEFAULT NULL,
  `member_id` int(11) NULL DEFAULT NULL COMMENT '成员ID',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending_assign' COMMENT '工单状态',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `accepted_at` datetime NULL DEFAULT NULL COMMENT '接单时间',
  `completed_at` datetime NULL DEFAULT NULL COMMENT '完成时间',
  `cancelled_at` datetime NULL DEFAULT NULL COMMENT '取消时间',
  `cancellation_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '取消原因',
  `dispatch_group_id` int(11) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `ix_work_orders_work_order_no`(`work_order_no`) USING BTREE,
  INDEX `task_id`(`task_id`) USING BTREE,
  INDEX `team_leader_id`(`team_leader_id`) USING BTREE,
  INDEX `member_id`(`member_id`) USING BTREE,
  INDEX `ix_work_orders_id`(`id`) USING BTREE,
  INDEX `idx_work_orders_detail_requirement_id`(`detail_requirement_id`) USING BTREE,
  CONSTRAINT `fk_work_orders_detail_requirement_id` FOREIGN KEY (`detail_requirement_id`) REFERENCES `task_detail_requirements` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `work_orders_ibfk_1` FOREIGN KEY (`task_id`) REFERENCES `tasks` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `work_orders_ibfk_2` FOREIGN KEY (`team_leader_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `work_orders_ibfk_3` FOREIGN KEY (`member_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 116 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of work_orders
-- ----------------------------

SET FOREIGN_KEY_CHECKS = 1;
